#include "jayess_runtime.h"
#include "picohttpparser.h"

#include <stddef.h>
#include <stdlib.h>
#include <string.h>

static char *jayess_http_copy_bytes(const char *data, size_t length) {
    char *copy = (char *) malloc(length + 1);
    if (copy == NULL) {
        return NULL;
    }
    if (data != NULL && length > 0) {
        memcpy(copy, data, length);
    }
    copy[length] = '\0';
    return copy;
}

static jayess_value *jayess_http_make_header_object(struct phr_header *headers, size_t header_count) {
    jayess_object *header_object = jayess_object_new();
    size_t i = 0;
    if (header_object == NULL) {
        return jayess_value_undefined();
    }
    for (i = 0; i < header_count; i++) {
        char *name = jayess_http_copy_bytes(headers[i].name, headers[i].name_len);
        char *value = jayess_http_copy_bytes(headers[i].value, headers[i].value_len);
        if (name == NULL || value == NULL) {
            free(name);
            free(value);
            continue;
        }
        jayess_object_set_value(header_object, name, jayess_value_from_string(value));
        free(name);
        free(value);
    }
    return jayess_value_from_object(header_object);
}

static jayess_value *jayess_http_make_request_object(const char *method, size_t method_len, const char *path, size_t path_len, int minor_version, struct phr_header *headers, size_t header_count, const char *body, size_t body_len) {
    jayess_object *request = jayess_object_new();
    jayess_value *header_object_value = NULL;
    char *method_copy = jayess_http_copy_bytes(method, method_len);
    char *path_copy = jayess_http_copy_bytes(path, path_len);
    char *query_copy = NULL;
    char *body_copy = jayess_http_copy_bytes(body, body_len);
    const char *query_start = NULL;
    size_t i = 0;
    if (request == NULL || method_copy == NULL || path_copy == NULL || body_copy == NULL) {
        free(method_copy);
        free(path_copy);
        free(body_copy);
        return jayess_value_undefined();
    }
    query_start = strchr(path_copy, '?');
    if (query_start != NULL) {
        query_copy = jayess_http_copy_bytes(query_start + 1, strlen(query_start + 1));
        ((char *) query_start)[0] = '\0';
    } else {
        query_copy = jayess_http_copy_bytes("", 0);
    }
    if (query_copy == NULL) {
        free(method_copy);
        free(path_copy);
        free(body_copy);
        return jayess_value_undefined();
    }
    jayess_object_set_value(request, "method", jayess_value_from_string(method_copy));
    jayess_object_set_value(request, "path", jayess_value_from_string(path_copy));
    jayess_object_set_value(request, "query", jayess_value_from_string(query_copy));
    jayess_object_set_value(request, "httpVersion", jayess_value_from_string(minor_version >= 1 ? "1.1" : "1.0"));
    jayess_object_set_value(request, "body", jayess_value_from_string(body_copy));
    header_object_value = jayess_http_make_header_object(headers, header_count);
    if (header_object_value == NULL || jayess_value_kind_of(header_object_value) != JAYESS_VALUE_OBJECT) {
        free(method_copy);
        free(path_copy);
        free(query_copy);
        free(body_copy);
        return jayess_value_undefined();
    }
    jayess_object_set_value(request, "headers", header_object_value);
    free(method_copy);
    free(path_copy);
    free(query_copy);
    free(body_copy);
    return jayess_value_from_object(request);
}

static jayess_value *jayess_http_make_incremental_result(int parsed, jayess_value *message) {
    jayess_object *result = jayess_object_new();
    if (result == NULL) {
        return jayess_value_undefined();
    }
    jayess_object_set_value(result, "complete", jayess_value_from_bool(parsed > 0));
    jayess_object_set_value(result, "consumed", jayess_value_from_number(parsed > 0 ? (double) parsed : 0.0));
    jayess_object_set_value(result, "message", message != NULL ? message : jayess_value_undefined());
    return jayess_value_from_object(result);
}

jayess_value *jayess_http_make_response_object(int status, const char *message, size_t message_len, int minor_version, struct phr_header *headers, size_t header_count, const char *body, size_t body_len) {
    jayess_object *response = jayess_object_new();
    jayess_value *header_object_value = NULL;
    char *reason_copy = jayess_http_copy_bytes(message, message_len);
    char *body_copy = jayess_http_copy_bytes(body, body_len);
    if (response == NULL || reason_copy == NULL || body_copy == NULL) {
        free(reason_copy);
        free(body_copy);
        return jayess_value_undefined();
    }
    jayess_object_set_value(response, "status", jayess_value_from_number((double) status));
    jayess_object_set_value(response, "reason", jayess_value_from_string(reason_copy));
    jayess_object_set_value(response, "httpVersion", jayess_value_from_string(minor_version >= 1 ? "1.1" : "1.0"));
    jayess_object_set_value(response, "body", jayess_value_from_string(body_copy));
    header_object_value = jayess_http_make_header_object(headers, header_count);
    if (header_object_value == NULL || jayess_value_kind_of(header_object_value) != JAYESS_VALUE_OBJECT) {
        free(reason_copy);
        free(body_copy);
        return jayess_value_undefined();
    }
    jayess_object_set_value(response, "headers", header_object_value);
    free(reason_copy);
    free(body_copy);
    return jayess_value_from_object(response);
}

jayess_value *jayess_http_parse_request_native(jayess_value *input) {
    const char *text = jayess_expect_string(input, "jayess_http_parse_request_native");
    const char *method = NULL;
    const char *path = NULL;
    int minor_version = 0;
    size_t method_len = 0;
    size_t path_len = 0;
    size_t header_count = 32;
    struct phr_header headers[32];
    int parsed = 0;
    size_t total_length = 0;
    size_t body_length = 0;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    if (text == NULL) {
        return jayess_value_undefined();
    }
    total_length = strlen(text);
    memset(headers, 0, sizeof(headers));
    parsed = phr_parse_request(text, total_length, &method, &method_len, &path, &path_len, &minor_version, headers, &header_count, 0);
    if (parsed <= 0) {
        jayess_throw_named_error("SyntaxError", parsed == -2 ? "incomplete HTTP request" : "malformed HTTP request");
        return jayess_value_undefined();
    }
    if ((size_t) parsed > total_length) {
        jayess_throw_named_error("SyntaxError", "malformed HTTP request");
        return jayess_value_undefined();
    }
    body_length = total_length - (size_t) parsed;
    return jayess_http_make_request_object(method, method_len, path, path_len, minor_version, headers, header_count, text + parsed, body_length);
}

