jayess_value *jayess_http_parse_request_incremental_native(jayess_value *input, jayess_value *last_len_value) {
    const char *text = jayess_expect_string(input, "jayess_http_parse_request_incremental_native");
    const char *method = NULL;
    const char *path = NULL;
    int minor_version = 0;
    size_t method_len = 0;
    size_t path_len = 0;
    size_t header_count = 32;
    struct phr_header headers[32];
    int parsed = 0;
    size_t total_length = 0;
    size_t body_length = 0;
    size_t last_len = 0;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    if (text == NULL) {
        return jayess_value_undefined();
    }
    total_length = strlen(text);
    if (last_len_value != NULL && !jayess_value_is_nullish(last_len_value)) {
        double n = jayess_value_to_number(last_len_value);
        if (n > 0) {
            last_len = (size_t) n;
        }
    }
    memset(headers, 0, sizeof(headers));
    parsed = phr_parse_request(text, total_length, &method, &method_len, &path, &path_len, &minor_version, headers, &header_count, last_len);
    if (parsed == -2) {
        return jayess_http_make_incremental_result(parsed, jayess_value_undefined());
    }
    if (parsed <= 0 || (size_t) parsed > total_length) {
        jayess_throw_named_error("SyntaxError", "malformed HTTP request");
        return jayess_value_undefined();
    }
    body_length = total_length - (size_t) parsed;
    return jayess_http_make_incremental_result(parsed, jayess_http_make_request_object(method, method_len, path, path_len, minor_version, headers, header_count, text + parsed, body_length));
}

