jayess_value *jayess_http_decode_chunked_native(jayess_value *input) {
    struct phr_chunked_decoder decoder;
    char *buffer = NULL;
    size_t bufsz = 0;
    ssize_t ret = 0;
    jayess_object *result = NULL;
    if (jayess_value_kind_of(input) == JAYESS_VALUE_STRING) {
        const char *text = jayess_expect_string(input, "jayess_http_decode_chunked_native");
        if (jayess_has_exception()) {
            return jayess_value_undefined();
        }
        if (text == NULL) {
            return jayess_value_undefined();
        }
        bufsz = strlen(text);
        buffer = jayess_http_copy_bytes(text, bufsz);
    } else {
        unsigned char *bytes = jayess_expect_bytes_copy(input, &bufsz, "jayess_http_decode_chunked_native");
        if (jayess_has_exception()) {
            return jayess_value_undefined();
        }
        if (bytes == NULL) {
            return jayess_value_undefined();
        }
        buffer = (char *) bytes;
    }
    if (buffer == NULL) {
        return jayess_value_undefined();
    }
    memset(&decoder, 0, sizeof(decoder));
    decoder.consume_trailer = 1;
    ret = phr_decode_chunked(&decoder, buffer, &bufsz);
    if (ret == -2) {
        result = jayess_object_new();
        if (result == NULL) {
            free(buffer);
            return jayess_value_undefined();
        }
        jayess_object_set_value(result, "complete", jayess_value_from_bool(0));
        jayess_object_set_value(result, "body", jayess_value_from_string(""));
        jayess_object_set_value(result, "remaining", jayess_value_from_number(0));
        free(buffer);
        return jayess_value_from_object(result);
    }
    if (ret < 0) {
        free(buffer);
        jayess_throw_named_error("SyntaxError", "malformed chunked body");
        return jayess_value_undefined();
    }
    result = jayess_object_new();
    if (result == NULL) {
        free(buffer);
        return jayess_value_undefined();
    }
    buffer[bufsz] = '\0';
    jayess_object_set_value(result, "complete", jayess_value_from_bool(1));
    jayess_object_set_value(result, "body", jayess_value_from_string(buffer));
    jayess_object_set_value(result, "remaining", jayess_value_from_number((double) ret));
    free(buffer);
    return jayess_value_from_object(result);
}
